import { useState } from "react";
import "./EMR.css";

export default function EMR() {
  const [activeTab, setActiveTab] = useState("notes");

  const [vitals, setVitals] = useState({
    hr: "",
    bpSys: "",
    bpDia: "",
    rr: "",
    spo2: "",
    temp: ""
  });

  return (
    <div className="emr-page">

      {/* ================= HEADER ================= */}
      <div className="emr-header">
        <div className="emr-header-left">
          <img
            src="https://i.pravatar.cc/60"
            alt="patient"
            className="avatar"
          />
          <div>
            <h2>John Doe · 45Y / Male</h2>
            <p>MRN: MRN-10233 | Visit ID: VIS-2026-011 OPD – General Medicine</p>
          </div>
        </div>

        <button className="open-visit">OPEN VISIT</button>
      </div>

      {/* ================= TABS ================= */}
      <div className="emr-tabs">
        <button
          className={activeTab === "notes" ? "active" : ""}
          onClick={() => setActiveTab("notes")}
        >
          Clinical Notes
        </button>

        <button
          className={activeTab === "vitals" ? "active" : ""}
          onClick={() => setActiveTab("vitals")}
        >
          Vitals
        </button>
      </div>

      {/* ================= CONTENT ================= */}
      <div className="emr-content">

        {/* ================= CLINICAL NOTES ================= */}
        {activeTab === "notes" && (
          <div className="card">

            <div className="form-group">
              <label>Chief Complaint</label>
              <input />
            </div>

            <div className="form-group">
              <label>History of Present Illness</label>
              <textarea rows="4" />
            </div>

            <div className="form-group">
              <label>Assessment</label>
              <textarea rows="3" />
            </div>

            <div className="form-group">
              <label>Plan</label>
              <textarea rows="3" />
            </div>

          </div>
        )}

        {/* ================= VITALS ================= */}
        {activeTab === "vitals" && (
          <div className="card">

            <h3>Vital Signs</h3>

            <div className="vitals-grid">

              <div>
                <label>Heart Rate (bpm)</label>
                <input
                  type="number"
                  value={vitals.hr}
                  onChange={(e) =>
                    setVitals({ ...vitals, hr: e.target.value })
                  }
                />
              </div>

              <div>
                <label>Blood Pressure (Sys)</label>
                <input
                  type="number"
                  value={vitals.bpSys}
                  onChange={(e) =>
                    setVitals({ ...vitals, bpSys: e.target.value })
                  }
                />
              </div>

              <div>
                <label>Blood Pressure (Dia)</label>
                <input
                  type="number"
                  value={vitals.bpDia}
                  onChange={(e) =>
                    setVitals({ ...vitals, bpDia: e.target.value })
                  }
                />
              </div>

              <div>
                <label>Respiratory Rate</label>
                <input
                  type="number"
                  value={vitals.rr}
                  onChange={(e) =>
                    setVitals({ ...vitals, rr: e.target.value })
                  }
                />
              </div>

              <div>
                <label>SpO₂ (%)</label>
                <input
                  type="number"
                  value={vitals.spo2}
                  onChange={(e) =>
                    setVitals({ ...vitals, spo2: e.target.value })
                  }
                />
              </div>

              <div>
                <label>Temperature (°C)</label>
                <input
                  type="number"
                  step="0.1"
                  value={vitals.temp}
                  onChange={(e) =>
                    setVitals({ ...vitals, temp: e.target.value })
                  }
                />
              </div>

            </div>

            <div className="nurse-box">
              <label>Nurse Name</label>
              <input placeholder="Enter nurse name" />
            </div>

          </div>
        )}

      </div>

      {/* ================= FOOTER ================= */}
      <div className="emr-footer">
        <button className="draft">Save Draft</button>
        <button className="complete">Complete Visit</button>
      </div>

    </div>
  );
}
